func solve(nums []int64) []int64 {
	n := len(nums)
	if n == 0 {
		return []int64{}
	}

	answer := make([]int64, n)

	// TotalOddSuffix tracks the count of odd numbers in nums[i+1...n-1]
	totalOddSuffix := int64(0)
	// TotalEvenSuffix tracks the count of even numbers in nums[i+1...n-1]
	totalEvenSuffix := int64(0)

	// Iterate backwards from the last element (i=n-1) down to the first element (i=0)
	for i := n - 1; i >= 0; i-- {
		// If i < n-1, there exists a suffix, so we calculate the score based on the current suffix counts
		if i < n-1 {
			isOdd := nums[i]%2 != 0

			if isOdd {
				// If nums[i] is odd, the score is the count of even numbers in the suffix
				answer[i] = totalEvenSuffix
			} else {
				// If nums[i] is even, the score is the count of odd numbers in the suffix
				answer[i] = totalOddSuffix
			}
		} else {
			// For the last element (i=n-1), the score is 0 (initialized by default)
			answer[i] = 0
		}

		// Update the suffix counts to include nums[i] for the next iteration (i-1)
		isOdd := nums[i]%2 != 0
		if isOdd {
			totalOddSuffix++
		} else {
			totalEvenSuffix++
		}
	}

	return answer
}
